"""
MKT Luke chapters 13-15 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-luke-13-15.py
Part 3 of 3 covering Luke 7-15.
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

# Key term decisions for Luke 13-15:
# μετανοέω (13:3,5) = "repent" — genuine turning, not merely regret
# ἀπώλλυμι (15:4-32) = "lost" / "destroy" — same root as "perish" in 13:3; echoes deliberate
# σπλαγχνίζομαι (15:20) = "had compassion" — visceral, gut-level compassion
# ἁμαρτωλός = "sinner" throughout — social category, not merely moral term
# The three lost parables (15:1-32) receive elevated T-tier cadence
# ἀγαπητός (15:31 "son") = "dear son" — covenant relationship language
# The Prodigal Son T-tier aims for narrative beauty while respecting the Greek

LUKE_13_15 = {
 "13": {
  "1": {"L":"There were some present at that very time who told him about the Galileans whose blood Pilate had mingled with their sacrifices.","M":"Now there were some present at that time who told Jesus about the Galileans whose blood Pilate had mixed with their sacrifices.","T":"Some people there told him about the Galileans whose blood Pilate had mingled with their sacrifices."},
  "2": {"L":"And he answered them: Do you think that these Galileans were worse sinners than all the other Galileans, because they suffered in this way?","M":"Jesus answered: Do you think that these Galileans were worse sinners than all the other Galileans because they suffered this way?","T":"Jesus replied: Do you suppose these Galileans were greater sinners than all other Galileans, because they suffered this way?"},
  "3": {"L":"No, I tell you; but unless you repent, you will all likewise perish.","M":"I tell you, no! But unless you repent, you too will all perish.","T":"No—I tell you. But unless you turn to God, you will all perish just as they did."},
  "4": {"L":"Or those eighteen on whom the tower in Siloam fell and killed them: do you think that they were worse offenders than all the others who lived in Jerusalem?","M":"Or those eighteen who died when the tower in Siloam fell on them—do you think they were more guilty than all the others living in Jerusalem?","T":"Or those eighteen people on whom the tower of Siloam fell and killed them—do you think they were greater offenders than everyone else in Jerusalem?"},
  "5": {"L":"No, I tell you; but unless you repent, you will all likewise perish.","M":"I tell you, no! But unless you repent, you too will all perish.","T":"No—I tell you. But unless you turn to God, you will all perish just like them."},
  "6": {"L":"And he told this parable: A man had a fig tree planted in his vineyard, and he came seeking fruit on it and found none.","M":"Then he told this parable: A man had a fig tree growing in his vineyard, and he went to look for fruit on it but did not find any.","T":"He told this parable: A man had a fig tree planted in his vineyard. He came looking for fruit on it—and found none."},
  "7": {"L":"And he said to the vinedresser: Look, for three years now I have come seeking fruit on this fig tree, and I find none. Cut it down. Why should it use up the ground?","M":"So he said to the man who took care of the vineyard, For three years now I've been coming to look for fruit on this fig tree and haven't found any. Cut it down! Why should it use up the soil?","T":"He said to the gardener: Look—for three years I've come looking for fruit on this tree and found nothing. Cut it down. Why should it go on wasting the soil?"},
  "8": {"L":"And he answered him: Sir, let it alone this year also, until I dig around it and put on manure.","M":"Sir, the man replied, leave it alone for one more year, and I'll dig around it and fertilise it.","T":"The gardener answered: Sir, give it one more year. I'll dig around it and add fertilizer."},
  "9": {"L":"Then if it should bear fruit next year, well and good; but if not, you can cut it down.","M":"If it bears fruit next year, fine! If not, then cut it down.","T":"If it bears fruit next year—good. If not, then cut it down."},
  "10": {"L":"Now he was teaching in one of the synagogues on the Sabbath.","M":"On a Sabbath Jesus was teaching in one of the synagogues,","T":"One Sabbath Jesus was teaching in a synagogue,"},
  "11": {"L":"And behold, there was a woman who had had a disabling spirit for eighteen years. She was bent over and could not fully straighten herself.","M":"and a woman was there who had been crippled by a spirit for eighteen years. She was bent over and could not straighten up at all.","T":"and a woman was there who had been bound by a crippling spirit for eighteen years. She was bent double and utterly unable to straighten herself."},
  "12": {"L":"When Jesus saw her, he called her over and said to her: Woman, you are freed from your disability.","M":"When Jesus saw her, he called her forward and said to her: Woman, you are set free from your infirmity.","T":"When Jesus saw her, he called her to him and said: Woman, you are released from your condition."},
  "13": {"L":"And he laid his hands on her, and immediately she was made straight, and she glorified God.","M":"Then he put his hands on her, and immediately she straightened up and praised God.","T":"He laid his hands on her—and immediately she straightened up and praised God."},
  "14": {"L":"But the ruler of the synagogue, indignant because Jesus had healed on the Sabbath, said to the people: There are six days in which work ought to be done. Come on those days and be healed, and not on the Sabbath day.","M":"Indignant because Jesus had healed on the Sabbath, the synagogue leader said to the people: There are six days for work. So come and be healed on those days, not on the Sabbath.","T":"The synagogue ruler, furious that Jesus had healed on the Sabbath, said to the crowd: There are six days for work—come to be healed on those days, not on the Sabbath."},
  "15": {"L":"Then the Lord answered him: You hypocrites! Does not each of you on the Sabbath untie his ox or his donkey from the manger and lead it away to water it?","M":"The Lord answered him: You hypocrites! Doesn't each of you on the Sabbath untie your ox or donkey from the stall and lead it out to give it water?","T":"The Lord answered: Hypocrites! Every one of you unties your ox or donkey from the stall on the Sabbath and leads it to water."},
  "16": {"L":"And ought not this woman, a daughter of Abraham whom Satan bound for eighteen years, be loosed from this bond on the Sabbath day?","M":"Then should not this woman, a daughter of Abraham, whom Satan has kept bound for eighteen long years, be set free on the Sabbath day from what bound her?","T":"And ought not this woman—a daughter of Abraham whom Satan has kept bound for eighteen years—be set free from her bondage on the Sabbath?"},
  "17": {"L":"As he said these things, all his adversaries were put to shame, and all the people rejoiced at all the glorious things that were done by him.","M":"When he said this, all his opponents were humiliated, but the people were delighted with all the wonderful things he was doing.","T":"When he said this, all his opponents were humiliated—but the whole crowd rejoiced at all the wonderful things he was doing."},
  "18": {"L":"He said therefore: What is the kingdom of God like? And to what shall I compare it?","M":"Then Jesus asked: What is the kingdom of God like? What shall I compare it to?","T":"Then he said: What is the kingdom of God like? To what shall I compare it?"},
  "19": {"L":"It is like a grain of mustard seed that a man took and sowed in his garden, and it grew and became a tree, and the birds of the air made nests in its branches.","M":"It is like a mustard seed, which a man took and planted in his garden. It grew and became a tree, and the birds perched in its branches.","T":"It is like a mustard seed that a man planted in his garden. It grew and became a tree, and the birds came and nested in its branches."},
  "20": {"L":"And again he said: To what shall I compare the kingdom of God?","M":"Again he asked: What shall I compare the kingdom of God to?","T":"Again he said: What shall I compare the kingdom of God to?"},
  "21": {"L":"It is like leaven that a woman took and hid in three measures of flour, until it was all leavened.","M":"It is like yeast that a woman took and mixed into about thirty kilograms of flour until it worked all through the dough.","T":"It is like yeast that a woman worked into a large batch of flour—until it had spread through the whole mass."},
  "22": {"L":"He went on his way through towns and villages, teaching and journeying toward Jerusalem.","M":"Then Jesus went through the towns and villages, teaching as he made his way to Jerusalem.","T":"Jesus traveled through towns and villages, teaching as he journeyed toward Jerusalem."},
  "23": {"L":"And someone said to him: Lord, will those who are saved be few? And he said to them:","M":"Someone asked him: Lord, are only a few people going to be saved? He said to them:","T":"Someone asked him: Lord, will only a few be saved? He replied:"},
  "24": {"L":"Strive to enter through the narrow door. For many, I tell you, will seek to enter and will not be able.","M":"Make every effort to enter through the narrow door, because many, I tell you, will try to enter and will not be able to.","T":"Strive to enter through the narrow door—because many will try and will not be able."},
  "25": {"L":"When once the master of the house has risen and shut the door, and you begin to stand outside and to knock at the door, saying: Lord, open to us, then he will answer you: I do not know where you come from.","M":"Once the owner of the house gets up and closes the door, you will stand outside knocking and pleading, Sir, open the door for us. But he will answer, I don't know you or where you come from.","T":"Once the master of the house gets up and bolts the door, and you stand outside knocking—Lord, open up for us!—he will answer: I don't know where you come from."},
  "26": {"L":"Then you will begin to say: We ate and drank in your presence, and you taught in our streets.","M":"Then you will say: We ate and drank with you, and you taught in our streets.","T":"Then you will say: We ate and drank with you—you taught in our streets!"},
  "27": {"L":"But he will say: I tell you, I do not know where you come from. Depart from me, all you workers of evil!","M":"But he will reply: I don't know you or where you come from. Away from me, all you evildoers!","T":"But he will say: I don't know you or where you come from. Get away from me—all you workers of evil."},
  "28": {"L":"In that place there will be weeping and gnashing of teeth, when you see Abraham and Isaac and Jacob and all the prophets in the kingdom of God but you yourselves cast out.","M":"There will be weeping there, and gnashing of teeth, when you see Abraham, Isaac and Jacob and all the prophets in the kingdom of God, but you yourselves thrown out.","T":"There will be weeping and grinding of teeth when you see Abraham and Isaac and Jacob and all the prophets inside the kingdom of God—and yourselves thrown out."},
  "29": {"L":"And people will come from east and west, and from north and south, and recline at table in the kingdom of God.","M":"People will come from east and west and north and south, and will take their places at the feast in the kingdom of God.","T":"People will come from east and west and north and south and take their places at the feast in God's kingdom."},
  "30": {"L":"And behold, some are last who will be first, and some are first who will be last.","M":"Indeed there are those who are last who will be first, and first who will be last.","T":"And there are those who are last who will be first—and first who will be last."},
  "31": {"L":"At that very hour some Pharisees came and said to him: Get away from here, for Herod wants to kill you.","M":"At that time some Pharisees came to Jesus and said to him: Leave this place and go somewhere else. Herod wants to kill you.","T":"At that moment some Pharisees came to him: Leave here and go somewhere else—Herod wants to kill you."},
  "32": {"L":"And he said to them: Go and tell that fox: Behold, I cast out demons and perform cures today and tomorrow, and the third day I finish my course.","M":"He replied: Go tell that fox, I will keep on driving out demons and healing people today and tomorrow, and on the third day I will reach my goal.","T":"He said: Go and tell that fox—I am driving out demons and performing healings today and tomorrow, and on the third day I complete my work."},
  "33": {"L":"Nevertheless, I must go on my way today and tomorrow and the day following, for it cannot be that a prophet should perish away from Jerusalem.","M":"In any case, I must press on today and tomorrow and the next day—for surely no prophet can die outside Jerusalem!","T":"But I must press on—today, tomorrow, and the day after—for it is unthinkable that a prophet should perish anywhere but Jerusalem."},
  "34": {"L":"O Jerusalem, Jerusalem, the city that kills the prophets and stones those who are sent to it! How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!","M":"Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing.","T":"Jerusalem, Jerusalem—you who kill the prophets and stone those sent to you! How many times I have longed to gather your children together the way a hen gathers her chicks under her wings—and you would not let me."},
  "35": {"L":"Behold, your house is forsaken. And I tell you, you will not see me until you say: Blessed is he who comes in the name of the Lord!","M":"Look, your house is left to you desolate. I tell you, you will not see me again until you say, Blessed is he who comes in the name of the Lord.","T":"Look—your house is abandoned to you. I tell you, you will not see me until the time comes when you say: Blessed is he who comes in the name of the Lord."}
 },
 "14": {
  "1": {"L":"One Sabbath, when he went to dine at the house of a ruler of the Pharisees, they were watching him carefully.","M":"One Sabbath, when Jesus went to eat in the house of a prominent Pharisee, he was being carefully watched.","T":"One Sabbath, Jesus went to eat at the home of a leading Pharisee—and they were watching him closely."},
  "2": {"L":"And behold, there was a man before him who had dropsy.","M":"There in front of him was a man suffering from abnormal swelling of his body.","T":"Right there before him was a man with dropsy."},
  "3": {"L":"And Jesus responded to the lawyers and Pharisees, saying: Is it lawful to heal on the Sabbath, or not?","M":"Jesus asked the Pharisees and experts in the law: Is it lawful to heal on the Sabbath or not?","T":"Jesus said to the lawyers and Pharisees: Is it lawful to heal on the Sabbath or not?"},
  "4": {"L":"But they remained silent. Then he took him and healed him and sent him away.","M":"But they remained silent. So taking hold of the man, he healed him and sent him on his way.","T":"They were silent. So Jesus took hold of the man, healed him, and sent him on his way."},
  "5": {"L":"And he said to them: Which of you, having a son or an ox that has fallen into a well on a Sabbath day, will not immediately pull him out?","M":"Then he asked them: If one of you has a child or an ox that falls into a well on the Sabbath day, will you not immediately pull it out?","T":"Then he asked them: If your child or your ox falls into a well on the Sabbath—which of you would not pull them out immediately?"},
  "6": {"L":"And they could not reply to these things.","M":"And they had nothing to say.","T":"They had no answer."},
  "7": {"L":"Now he told a parable to those who were invited, when he noticed how they chose the places of honor, saying to them:","M":"When he noticed how the guests picked the places of honour at the table, he told them this parable:","T":"He noticed how the guests were choosing the places of honor, and told them this parable:"},
  "8": {"L":"When you are invited by someone to a wedding feast, do not sit down in a place of honor, lest someone more distinguished than you be invited by him,","M":"When someone invites you to a wedding feast, do not take the place of honour, for a person more distinguished than you may have been invited.","T":"When someone invites you to a wedding banquet, don't take the place of honor—someone more distinguished than you may have been invited,"},
  "9": {"L":"and he who invited you both will come and say to you: Give your place to this person, and then you will begin with shame to take the lowest place.","M":"If so, the host who invited both of you will come and say to you, Give this person your seat. Then, humiliated, you will have to take the least important place.","T":"and the host who invited you both may come and say to you: Give this person your seat. Then in humiliation you will have to move to the lowest place."},
  "10": {"L":"But when you are invited, go and sit in the lowest place, so that when your host comes he may say to you: Friend, move up higher. Then you will be honored in the presence of all who sit at table with you.","M":"But when you are invited, take the lowest place, so that when your host comes, he will say to you, Friend, move up to a better place. Then you will be honoured in the presence of all the other guests.","T":"But when you are invited, take the lowest place—so that when your host comes he can say: Friend, move up to a better seat. Then you will be honored in front of everyone at the table."},
  "11": {"L":"For everyone who exalts himself will be humbled, and everyone who humbles himself will be exalted.","M":"For all those who exalt themselves will be humbled, and those who humble themselves will be exalted.","T":"For everyone who exalts himself will be brought low—and everyone who humbles himself will be lifted up."},
  "12": {"L":"He said also to the man who had invited him: When you give a dinner or a banquet, do not invite your friends or your brothers or your relatives or rich neighbors, lest they also invite you in return and you be repaid.","M":"Then Jesus said to his host: When you give a luncheon or dinner, do not invite your friends, your brothers or sisters, your relatives, or your rich neighbours; if you do, they may invite you back and so you will be repaid.","T":"He also said to the man who had invited him: When you host a lunch or dinner, don't invite your friends, brothers, relatives, or wealthy neighbors—they will invite you back, and you will be repaid."},
  "13": {"L":"But when you give a feast, invite the poor, the crippled, the lame, the blind,","M":"But when you give a banquet, invite the poor, the crippled, the lame, the blind,","T":"Instead, when you give a feast, invite the poor, the crippled, the lame, the blind."},
  "14": {"L":"and you will be blessed, because they cannot repay you. For you will be repaid at the resurrection of the just.","M":"and you will be blessed. Although they cannot repay you, you will be repaid at the resurrection of the righteous.","T":"Then you will be truly blessed—because they cannot repay you. You will be repaid at the resurrection of the righteous."},
  "15": {"L":"When one of those who reclined at table with him heard these things, he said to him: Blessed is everyone who will eat bread in the kingdom of God!","M":"When one of those at the table with him heard this, he said to Jesus: Blessed is the one who will eat at the feast in the kingdom of God.","T":"One of the guests who heard this said: Blessed is everyone who will eat at the banquet in God's kingdom!"},
  "16": {"L":"But he said to him: A man once gave a great banquet and invited many.","M":"Jesus replied: A certain man was preparing a great banquet and invited many guests.","T":"Jesus replied: A man once prepared a great banquet and invited many guests."},
  "17": {"L":"And at the time for the banquet he sent his servant to say to those who had been invited: Come, for everything is now ready.","M":"At the time of the banquet he sent his servant to tell those who had been invited, Come, for everything is now ready.","T":"When the time came, he sent his servant to tell the invited guests: Come—everything is ready now."},
  "18": {"L":"But they all alike began to make excuses. The first said to him: I have bought a field, and I must go out and see it. Please have me excused.","M":"But they all alike began to make excuses. The first said: I have just bought a field, and I must go and see it. Please excuse me.","T":"But they all—every one—began making excuses. The first said: I have just bought a field and need to go inspect it. Please excuse me."},
  "19": {"L":"And another said: I have bought five yoke of oxen, and I go to examine them. Please have me excused.","M":"Another said: I have just bought five yoke of oxen, and I'm on my way to try them out. Please excuse me.","T":"Another said: I've just bought five yoke of oxen and I'm going to try them out. Please excuse me."},
  "20": {"L":"And another said: I have married a wife, and therefore I cannot come.","M":"Still another said: I have just got married, so I can't come.","T":"Another said: I have just married—I can't come."},
  "21": {"L":"So the servant came and reported these things to his master. Then the master of the house became angry and said to his servant: Go out quickly to the streets and lanes of the city, and bring in the poor and crippled and blind and lame.","M":"The servant came back and reported this to his master. Then the owner of the house became angry and ordered his servant: Go out quickly into the streets and alleys of the town and bring in the poor, the crippled, the blind and the lame.","T":"The servant returned and reported this to the master. Angry, the master told his servant: Go out immediately into the streets and alleys of the city—bring in the poor, the crippled, the blind, and the lame."},
  "22": {"L":"And the servant said: Sir, what you commanded has been done, and still there is room.","M":"Sir, the servant said, what you ordered has been done, but there is still room.","T":"The servant said: Sir, what you ordered has been done—and there is still room."},
  "23": {"L":"And the master said to the servant: Go out to the highways and hedges and compel people to come in, that my house may be filled.","M":"Then the master told his servant: Go out to the roads and country lanes and compel them to come in, so that my house will be full.","T":"The master said: Go out to the roads and the hedgerows and bring people in—persuade them to come—so that my house will be full."},
  "24": {"L":"For I tell you, none of those men who were invited shall taste my banquet.","M":"I tell you, not one of those who were invited will get a taste of my banquet.","T":"I tell you, not one of those originally invited will taste a single bite of my banquet."},
  "25": {"L":"Now great crowds accompanied him, and he turned and said to them:","M":"Large crowds were travelling with Jesus, and turning to them he said:","T":"Large crowds were traveling with him. He turned and said to them:"},
  "26": {"L":"If anyone comes to me and does not hate his own father and mother and wife and children and brothers and sisters, yes, and even his own life, he cannot be my disciple.","M":"If anyone comes to me and does not hate father and mother, wife and children, brothers and sisters—yes, even their own life—such a person cannot be my disciple.","T":"If anyone comes to me without placing me before father and mother, wife and children, brothers and sisters—yes, even their own life—that person cannot be my disciple."},
  "27": {"L":"Whoever does not bear his own cross and come after me cannot be my disciple.","M":"And whoever does not carry their cross and follow me cannot be my disciple.","T":"And whoever does not carry their own cross and follow me cannot be my disciple."},
  "28": {"L":"For which of you, desiring to build a tower, does not first sit down and count the cost, whether he has enough to complete it?","M":"Suppose one of you wants to build a tower. Won't you first sit down and estimate the cost to see if you have enough money to complete it?","T":"Which of you, wanting to build a tower, doesn't first sit down and calculate the cost to see if you have enough to finish it?"},
  "29": {"L":"Otherwise, when he has laid a foundation and is not able to finish, all who see it begin to mock him,","M":"For if you lay the foundation and are not able to finish it, everyone who sees it will ridicule you,","T":"If you lay the foundation but can't finish, everyone who sees it will mock you—"},
  "30": {"L":"saying: This man began to build and was not able to finish.","M":"saying, This person began to build and wasn't able to finish.","T":"saying: This person started building and couldn't complete it."},
  "31": {"L":"Or what king, going out to encounter another king in war, will not sit down first and deliberate whether he is able with ten thousand to meet him who comes against him with twenty thousand?","M":"Or suppose a king is about to go to war against another king. Won't he first sit down and consider whether he is able with ten thousand men to oppose the one coming against him with twenty thousand?","T":"Or what king, heading into war against another king, doesn't first sit down and think through whether his ten thousand troops can face the other's twenty thousand?"},
  "32": {"L":"And if not, while the other is yet a great way off, he sends a delegation and asks for terms of peace.","M":"If he is not able, he will send a delegation while the other is still a long way off and will ask for terms of peace.","T":"If he can't, he sends envoys while the enemy is still far off and asks for terms of peace."},
  "33": {"L":"So therefore, any one of you who does not renounce all that he has cannot be my disciple.","M":"In the same way, those of you who do not give up everything you have cannot be my disciples.","T":"In the same way, any of you who does not give up everything they have cannot be my disciple."},
  "34": {"L":"Salt is good, but if salt has lost its taste, how shall its saltiness be restored?","M":"Salt is good, but if it loses its saltiness, how can it be made salty again?","T":"Salt is good—but if salt loses its flavor, what can restore it?"},
  "35": {"L":"It is of no use either for the soil or for the manure pile. It is thrown away. He who has ears to hear, let him hear.","M":"It is fit neither for the soil nor for the manure pile; it is thrown out. Whoever has ears to hear, let them hear.","T":"It is useless for the soil or the compost heap—it gets thrown away. Whoever has ears to hear, let them hear."}
 },
 "15": {
  "1": {"L":"Now the tax collectors and sinners were all drawing near to hear him.","M":"Now the tax collectors and sinners were all gathering round to hear Jesus.","T":"All the tax collectors and sinners were crowding close to hear Jesus."},
  "2": {"L":"And the Pharisees and the scribes grumbled, saying: This man receives sinners and eats with them.","M":"But the Pharisees and the teachers of the law muttered: This man welcomes sinners and eats with them.","T":"The Pharisees and religious scholars grumbled: This man welcomes sinners and actually eats with them."},
  "3": {"L":"So he told them this parable:","M":"Then Jesus told them this parable:","T":"So he told them this parable:"},
  "4": {"L":"What man of you, having a hundred sheep, if he has lost one of them, does not leave the ninety-nine in the open country, and go after the one that is lost, until he finds it?","M":"Suppose one of you has a hundred sheep and loses one of them. Doesn't he leave the ninety-nine in the open country and go after the lost sheep until he finds it?","T":"Suppose you have a hundred sheep and lose one. Don't you leave the ninety-nine out in the open and go after the lost one until you find it?"},
  "5": {"L":"And when he has found it, he lays it on his shoulders, rejoicing.","M":"And when he finds it, he joyfully puts it on his shoulders","T":"And when you find it, you lift it onto your shoulders with joy."},
  "6": {"L":"And when he comes home, he calls together his friends and his neighbors, saying to them: Rejoice with me, for I have found my sheep that was lost.","M":"and goes home. Then he calls his friends and neighbours together and says, Rejoice with me; I have found my lost sheep.","T":"You come home and call together your friends and neighbors: Celebrate with me—I have found my lost sheep!"},
  "7": {"L":"Just so, I tell you, there will be more joy in heaven over one sinner who repents than over ninety-nine righteous persons who need no repentance.","M":"I tell you that in the same way there will be more rejoicing in heaven over one sinner who repents than over ninety-nine righteous persons who do not need to repent.","T":"I tell you—there is more joy in heaven over one sinner who turns back to God than over ninety-nine righteous people who have no need to repent."},
  "8": {"L":"Or what woman, having ten silver coins, if she loses one coin, does not light a lamp and sweep the house and seek diligently until she finds it?","M":"Or suppose a woman has ten silver coins and loses one. Doesn't she light a lamp, sweep the house and search carefully until she finds it?","T":"Or suppose a woman has ten silver coins and loses one. Doesn't she light a lamp and sweep the whole house, searching carefully until she finds it?"},
  "9": {"L":"And when she has found it, she calls together her friends and neighbors, saying: Rejoice with me, for I have found the coin that I had lost.","M":"And when she finds it, she calls her friends and neighbours together and says, Rejoice with me; I have found my lost coin.","T":"And when she finds it, she calls her friends and neighbors: Celebrate with me—I found the coin I had lost!"},
  "10": {"L":"Just so, I tell you, there is joy before the angels of God over one sinner who repents.","M":"In the same way, I tell you, there is rejoicing in the presence of the angels of God over one sinner who repents.","T":"I tell you, there is joy among God's angels over one sinner who turns back to God."},
  "11": {"L":"And he said: There was a man who had two sons.","M":"Jesus continued: There was a man who had two sons.","T":"Jesus continued: A man had two sons."},
  "12": {"L":"And the younger of them said to his father: Father, give me the share of property that is coming to me. And he divided his property between them.","M":"The younger one said to his father, Father, give me my share of the estate. So he divided his property between them.","T":"The younger said to his father: Father, give me my share of the estate. So the father divided his property between them."},
  "13": {"L":"Not many days later, the younger son gathered all he had and took a journey into a far country, and there he squandered his property in reckless living.","M":"Not long after that, the younger son got together all he had, set off for a distant country and there squandered his wealth in wild living.","T":"Not many days later, the younger son packed everything up and left for a distant country—where he wasted his entire inheritance in reckless living."},
  "14": {"L":"And when he had spent everything, a severe famine arose in that country, and he began to be in need.","M":"After he had spent everything, there was a severe famine in that whole country, and he began to be in need.","T":"After he had spent everything, a severe famine struck that country—and he began to go hungry."},
  "15": {"L":"So he went and hired himself out to one of the citizens of that country, who sent him into his fields to feed pigs.","M":"So he went and hired himself out to a citizen of that country, who sent him to his fields to feed pigs.","T":"He went and attached himself to a citizen of that country, who sent him out to feed pigs."},
  "16": {"L":"And he was longing to be fed with the pods that the pigs ate, and no one gave him anything.","M":"He longed to fill his stomach with the pods that the pigs were eating, but no one gave him anything.","T":"He was so hungry he would gladly have eaten the pigs' food—but no one gave him anything."},
  "17": {"L":"But when he came to himself, he said: How many of my father's hired servants have more than enough bread, but I perish here with hunger!","M":"When he came to his senses, he said: How many of my father's hired servants have food to spare, and here I am starving to death!","T":"Then he came to his senses. He said: How many of my father's hired workers have more than enough to eat—and here I am dying of hunger!"},
  "18": {"L":"I will arise and go to my father, and I will say to him: Father, I have sinned against heaven and before you.","M":"I will set out and go back to my father and say to him: Father, I have sinned against heaven and against you.","T":"I will get up and go to my father and say: Father, I have sinned against heaven and against you."},
  "19": {"L":"I am no longer worthy to be called your son. Treat me as one of your hired servants.","M":"I am no longer worthy to be called your son; make me like one of your hired servants.","T":"I am no longer worthy to be called your son—make me like one of your hired workers."},
  "20": {"L":"And he arose and came to his father. But while he was still a long way off, his father saw him and felt compassion, and ran and embraced him and kissed him.","M":"So he got up and went to his father. But while he was still a long way off, his father saw him and was filled with compassion for him; he ran to his son, threw his arms round him and kissed him.","T":"So he got up and set out toward his father. While he was still far down the road, his father saw him—his heart broke with compassion. He ran, threw his arms around him, and kissed him."},
  "21": {"L":"And the son said to him: Father, I have sinned against heaven and before you. I am no longer worthy to be called your son.","M":"The son said to him: Father, I have sinned against heaven and against you. I am no longer worthy to be called your son.","T":"The son said: Father, I have sinned against heaven and against you. I am no longer worthy to be called your son."},
  "22": {"L":"But the father said to his servants: Bring quickly the best robe, and put it on him, and put a ring on his hand, and shoes on his feet.","M":"But the father said to his servants: Quick! Bring the best robe and put it on him. Put a ring on his finger and sandals on his feet.","T":"But the father said to his servants: Quick—bring the best robe and put it on him! Put a ring on his finger and sandals on his feet."},
  "23": {"L":"And bring the fattened calf and kill it, and let us eat and celebrate.","M":"Bring the fattened calf and kill it. Let's have a feast and celebrate.","T":"Bring the fattened calf and slaughter it—let's eat and celebrate!"},
  "24": {"L":"For this my son was dead, and is alive again; he was lost, and is found. And they began to celebrate.","M":"For this son of mine was dead and is alive again; he was lost and is found. So they began to celebrate.","T":"For this son of mine was dead—and is alive again! He was lost—and is found! And the celebration began."},
  "25": {"L":"Now his older son was in the field, and as he came and drew near to the house, he heard music and dancing.","M":"Meanwhile, the older son was in the field. When he came near the house, he heard music and dancing.","T":"His older son was out in the field. As he came near the house, he heard music and dancing."},
  "26": {"L":"And he called one of the servants and asked what these things meant.","M":"So he called one of the servants and asked him what was going on.","T":"He called one of the servants and asked what was happening."},
  "27": {"L":"And he said to him: Your brother has come, and your father has killed the fattened calf, because he has received him back safe and sound.","M":"Your brother has come, he replied, and your father has killed the fattened calf because he has him back safe and sound.","T":"The servant said: Your brother has come back—your father has slaughtered the fattened calf because he has him home safe and sound."},
  "28": {"L":"But he was angry and refused to go in. His father came out and entreated him,","M":"The older brother became angry and refused to go in. So his father went out and pleaded with him.","T":"The older brother was furious and refused to go in. His father came out and pleaded with him."},
  "29": {"L":"but he answered his father: Look, these many years I have been serving you, and I never disobeyed your command, yet you never gave me a young goat, that I might celebrate with my friends.","M":"But he answered his father: Look! All these years I've been slaving for you and never disobeyed your orders. Yet you never gave me even a young goat so I could celebrate with my friends.","T":"But he answered his father: Look—all these years I have worked for you like a slave and never once disobeyed your orders. You never gave me even a goat to celebrate with my friends."},
  "30": {"L":"But when this son of yours came, who has devoured your property with prostitutes, you killed the fattened calf for him!","M":"But when this son of yours who has squandered your property with prostitutes comes home, you kill the fattened calf for him!","T":"But when this son of yours shows up—the one who has blown your money on prostitutes—you slaughter the fattened calf for him!"},
  "31": {"L":"And he said to him: Son, you are always with me, and all that is mine is yours.","M":"My son, the father said, you are always with me, and everything I have is yours.","T":"His father said: Son—you are always with me. Everything I have is yours."},
  "32": {"L":"It was fitting to celebrate and be glad, for this your brother was dead, and is alive; he was lost, and is found.","M":"But we had to celebrate and be glad, because this brother of yours was dead and is alive again; he was lost and is found.","T":"But we had to celebrate—we had to be glad. Your brother was dead and is alive. He was lost and is found."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'luke')
        for ch, verses in LUKE_13_15.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'luke', data)
    print('Luke chapters 13-15 written.')

if __name__ == '__main__':
    main()
